**Idea:**

We build two arrays:



**Array PPP:**

P[i]P[i]P[i] represents the maximum score obtainable when moving (with moves of +1+1+1 or +2+2+2) from square 111 (index 000 in 0-indexed notation) to square i+1i+1i+1.

This dp formulation is similar to many “step” problems and obeys the recurrence:
P[i]=A[i]+max⁡(P[i−1], P[i−2])P[i] = A[i] + \max(P[i-1],\, P[i-2])P[i]=A[i]+max(P[i−1],P[i−2])

with base condition P[0]=A[0]P[0]=A[0]P[0]=A[0].




**Array QQQ:**

Q[i]Q[i]Q[i] represents the maximum score obtainable when moving (with moves of +1+1+1 or +2+2+2) from the starting square kkk (converted to 0-index) to square i+1i+1i+1.

We set Q[k]=A[k]Q[k]=A[k]Q[k]=A[k] and for i&gt;ki &gt; ki&gt;k use:
Q[i]=A[i]+max⁡(Q[i−1], Q[i−2])Q[i] = A[i] + \max(Q[i-1],\, Q[i-2])Q[i]=A[i]+max(Q[i−1],Q[i−2])



**Combining Phases:**

The turning point where Calvin switches from forward to backward phase is an index iii (with i≥ki \ge ki≥k). When combining the two phases, note that:


The forward phase (from kkk to iii) contributes Q[i]Q[i]Q[i], but since Q[k]Q[k]Q[k] initially includes A[k]A[k]A[k] (which should not be added), we subtract A[k]A[k]A[k].
The backward phase (from iii to 111) is computed using the PPP array. However, the turning square iii gets counted in both P[i]P[i]P[i] and Q[i]Q[i]Q[i], so we subtract A[i]A[i]A[i] once.
Thus, for a chosen turning point iii, the score obtained is:

score=(P[i]−A[i])+(Q[i]−A[k])\text{score} = \Bigl(P[i] - A[i]\Bigr) + \Bigl(Q[i] - A[k]\Bigr)score=(P[i]−A[i])+(Q[i]−A[k])

We try all possible turning points i∈[k,N−1]i\in [k, N-1]i∈[k,N−1] and take the maximum value.

The following code implementations provide this approach in both **C++** and **Python**.

`#include &lt;bits/stdc++.h&gt;
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, k;
    cin &gt;&gt; N &gt;&gt; k;
    k--; // Convert to 0-index
    vector&lt;int&gt; A(N);
    for (int i = 0; i &lt; N; i++){
        cin &gt;&gt; A[i];
    }

    // P[i] = maximum score from square 1 to square i+1 (0-indexed)
    vector&lt;int&gt; P(N, 0), Q(N, 0);
    P[0] = A[0];
    for (int i = 1; i &lt; N; i++){
        P[i] = A[i] + P[i-1];
        if (i &gt;= 2)
            P[i] = max(P[i], A[i] + P[i-2]);
    }

    // Q[i] = maximum score from square k to square i+1 (forward phase starting at k)
    Q[k] = A[k];
    for (int i = k+1; i &lt; N; i++){
        Q[i] = A[i] + Q[i-1];
        if (i &gt;= k+2)
            Q[i] = max(Q[i], A[i] + Q[i-2]);
    }

    // Combine the forward and backward phases.
    // For turning point i, score = (P[i] - A[i]) + (Q[i] - A[k]).
    // For i = k (i.e. no forward moves), the score is P[k] - A[k].
    int ans = P[k] - A[k];
    for (int i = k+1; i &lt; N; i++){
        ans = max(ans, (P[i] - A[i]) + (Q[i] - A[k]));
    }

    cout &lt;&lt; ans &lt;&lt; "\n";
    return 0;
}
``def main():
    import sys
    input_data = sys.stdin.read().strip().split()
    if not input_data:
        return
    it = iter(input_data)
    N = int(next(it))
    k = int(next(it)) - 1   # Convert to 0-index
    A = [int(next(it)) for _ in range(N)]

    # Build DP array P to compute maximum score from square 1 to each square.
    P = [0] * N
    P[0] = A[0]
    for i in range(1, N):
        P[i] = A[i] + P[i-1]
        if i &gt;= 2:
            P[i] = max(P[i], A[i] + P[i-2])

    # Build DP array Q for forward moves from square k.
    Q = [0] * N
    Q[k] = A[k]
    for i in range(k+1, N):
        Q[i] = A[i] + Q[i-1]
        if i &gt;= k+2:
            Q[i] = max(Q[i], A[i] + Q[i-2])

    ans = P[k] - A[k]  # Candidate if turning point is k itself.
    for i in range(k+1, N):
        candidate = (P[i] - A[i]) + (Q[i] - A[k])
        ans = max(ans, candidate)

    sys.stdout.write(str(ans))

if __name__ == "__main__":
    main()
`**Idea:**

An alternative way is to define two dp arrays directly corresponding to the two phases, with careful treatment of initial conditions to avoid double counting:



**Forward DP Array (`dp_forward`):**

We define `dp_forward[i]` as the maximum score achievable from the starting square kkk to square iii (without counting the number on square kkk).

Initialize:

dp_forward[k]=0dp\_forward[k] = 0dp_forward[k]=0

For i&gt;ki &gt; ki&gt;k, use:
dp_forward[i]=A[i]+max⁡(dp_forward[i−1], dp_forward[i−2])dp\_forward[i] = A[i] + \max(dp\_forward[i-1],\, dp\_forward[i-2])dp_forward[i]=A[i]+max(dp_forward[i−1],dp_forward[i−2])

(only if those indices are valid, i.e. ≥k\ge k≥k).




**Backward DP Array (`dp_backward`):**

We define `dp_backward[i]` as the maximum score obtainable from square iii to square 111. By reversing the direction, this becomes similar to a forward dp starting at square 111, so we have:
dp_backward[0]=A[0]dp\_backward[0] = A[0]dp_backward[0]=A[0]

and for i≥1i \ge 1i≥1:
dp_backward[i]=A[i]+max⁡(dp_backward[i−1], dp_backward[i−2])dp\_backward[i] = A[i] + \max(dp\_backward[i-1],\, dp\_backward[i-2])dp_backward[i]=A[i]+max(dp_backward[i−1],dp_backward[i−2])



**Combining Phases:**

For a turning point iii, the total score is the sum of the forward and backward scores, but the number at square iii is counted twice. Hence, we subtract A[i]A[i]A[i] once:

score=dp_forward[i]+dp_backward[i]−A[i]\text{score} = dp\_forward[i] + dp\_backward[i] - A[i]score=dp_forward[i]+dp_backward[i]−A[i]

We iterate over all possible turning points i∈[k,N−1]i\in[k, N-1]i∈[k,N−1] and choose the maximum value.

The code implementations below reflect this approach in both C++ and Python.

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, k;
    cin &gt;&gt; N &gt;&gt; k;
    k--; // Convert to 0-index
    vector&lt;int&gt; A(N);
    for (int i = 0; i &lt; N; i++){
        cin &gt;&gt; A[i];
    }

    // dp_forward[i]: maximum score from starting square k to square i (excluding A[k])
    const int INF = 1000000000; // A large number for initialisation.
    vector&lt;int&gt; dp_forward(N, -INF);
    dp_forward[k] = 0;
    for (int i = k+1; i &lt; N; i++){
        if (i - 1 &gt;= k)
            dp_forward[i] = max(dp_forward[i], dp_forward[i-1] + A[i]);
        if (i - 2 &gt;= k)
            dp_forward[i] = max(dp_forward[i], dp_forward[i-2] + A[i]);
    }

    // dp_backward[i]: maximum score from square i to square 1 (index 0)
    vector&lt;int&gt; dp_backward(N, -INF);
    dp_backward[0] = A[0];
    if (N &gt; 1)
        dp_backward[1] = A[1] + dp_backward[0];
    for (int i = 2; i &lt; N; i++){
        dp_backward[i] = A[i] + max(dp_backward[i-1], dp_backward[i-2]);
    }

    int ans = -INF;
    for (int i = k; i &lt; N; i++){
        int candidate = dp_forward[i] + dp_backward[i] - A[i];
        ans = max(ans, candidate);
    }
    cout &lt;&lt; ans &lt;&lt; "\n";
    return 0;
}
``def main():
    import sys
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    k = int(next(it)) - 1  # Convert to 0-index
    A = [int(next(it)) for _ in range(N)]

    INF = 10**9
    # dp_forward: maximum score from square k to square i (forward phase), not including A[k].
    dp_forward = [-INF] * N
    dp_forward[k] = 0
    for i in range(k+1, N):
        if i - 1 &gt;= k:
            dp_forward[i] = max(dp_forward[i], dp_forward[i-1] + A[i])
        if i - 2 &gt;= k:
            dp_forward[i] = max(dp_forward[i], dp_forward[i-2] + A[i])

    # dp_backward: maximum score from square i to square 1.
    dp_backward = [-INF] * N
    dp_backward[0] = A[0]
    if N &gt; 1:
        dp_backward[1] = A[1] + dp_backward[0]
    for i in range(2, N):
        dp_backward[i] = A[i] + max(dp_backward[i-1], dp_backward[i-2])

    ans = -INF
    for i in range(k, N):
        candidate = dp_forward[i] + dp_backward[i] - A[i]
        ans = max(ans, candidate)

    sys.stdout.write(str(ans))

if __name__ == "__main__":
    main()
`Both approaches have a time complexity of O(N)O(N)O(N) and use very similar recurrences. The first approach closely mirrors the provided reference solution by precomputing two arrays and then combining them carefully; the second approach is a direct formulation by defining dp arrays for the forward and backward phases with adjusted initial conditions.

